import anthropic, json, subprocess
from pathlib import Path

client = anthropic.Anthropic()

def get_prompt_for_branch(branch: str) -> str:
    """Read the prompt file from a release branch without switching the working tree."""
    result = subprocess.run(
        ["git", "show", f"origin/{branch}:prompts/system_prompt.json"],
        capture_output=True, text=True
    )
    if result.returncode != 0:
        raise RuntimeError(f"Could not read prompt from {branch}: {result.stderr}")
    return json.loads(result.stdout)["system"]

def run_evals_on_branch(branch: str, spec_path: str) -> dict:
    system_prompt = get_prompt_for_branch(branch)
    spec = json.loads(Path(spec_path).read_text())
    failures = []

    for case in spec["eval_cases"]:
        resp = client.messages.create(
            model="claude-haiku-4-5-20251001",
            max_tokens=512,
            system=system_prompt,
            messages=[{"role": "user", "content": case["input"]}]
        )
        output = resp.content[0].text
        violations = [r for r in case.get("must_not_do", []) if r.lower() in output.lower()]
        if violations:
            failures.append({"case_id": case["id"], "violations": violations})

    return {
        "branch": branch,
        "total": len(spec["eval_cases"]),
        "failed": len(failures),
        "gate_passed": len(failures) == 0,
        "failures": failures,
    }

def validate_hotfix_across_release_branches(release_branches: list, spec_path: str) -> bool:
    all_passed = True
    for branch in release_branches:
        result = run_evals_on_branch(branch, spec_path)
        status = "PASS" if result["gate_passed"] else "FAIL"
        print(f"{status}: {branch} — {result['total'] - result['failed']}/{result['total']} passed")
        for f in result["failures"]:
            print(f"  FAIL {f['case_id']}: {f['violations']}")
        if not result["gate_passed"]:
            all_passed = False
    return all_passed

if __name__ == "__main__":
    branches = ["release/2025-Q2-v1", "release/2025-Q3-v1"]
    ok = validate_hotfix_across_release_branches(branches, "specs/behaviour_spec.json")
    import sys; sys.exit(0 if ok else 1)
